import{_ as a,o as t,c as o,a0 as s}from"./chunks/framework.BjpW4enL.js";const u=JSON.parse('{"title":"T4 Graph — Normas Estruturais","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/T4_GRAPH_NORMS.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/T4_GRAPH_NORMS.md","lastUpdated":1782593311000}'),d={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/T4_GRAPH_NORMS.md"};function i(r,e,n,c,l,p){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="t4-graph-—-normas-estruturais" tabindex="-1">T4 Graph — Normas Estruturais <a class="header-anchor" href="#t4-graph-—-normas-estruturais" aria-label="Permalink to &quot;T4 Graph — Normas Estruturais&quot;">​</a></h1><h2 id="_1-nos-nodes" tabindex="-1">1. Nós (Nodes) <a class="header-anchor" href="#_1-nos-nodes" aria-label="Permalink to &quot;1. Nós (Nodes)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Kind</th><th>Representa</th><th>Exemplo</th></tr></thead><tbody><tr><td>4</td><td><code>file</code></td><td>Arquivo físico no disco</td><td>899 nós ativos</td></tr><tr><td>2</td><td>—</td><td>Chunk semântico (L2 summary)</td><td>18.924 nós</td></tr><tr><td>1</td><td>—</td><td>Chunk estrutural (AST)</td><td>498 nós</td></tr><tr><td>0</td><td>—</td><td>Chunk raw (código fonte)</td><td>19.144 nós</td></tr></tbody></table><p>Nós <code>file</code> (level=4) têm <code>metadata.file_type</code>:</p><table tabindex="0"><thead><tr><th>file_type</th><th>Quantidade</th></tr></thead><tbody><tr><td>typescript</td><td>313</td></tr><tr><td>markdown</td><td>267</td></tr><tr><td>sql</td><td>141</td></tr><tr><td>python</td><td>69</td></tr><tr><td>json</td><td>55</td></tr><tr><td>yaml, rust, outros</td><td>54</td></tr></tbody></table><h2 id="_2-arestas-edges-—-angulos-de-projecao" tabindex="-1">2. Arestas (Edges) — Ângulos de Projeção <a class="header-anchor" href="#_2-arestas-edges-—-angulos-de-projecao" aria-label="Permalink to &quot;2. Arestas (Edges) — Ângulos de Projeção&quot;">​</a></h2><p>Cada <code>criteria</code> projeta uma visão diferente do sistema. Agentes navegam por uma ou combinação delas.</p><h3 id="part-of-38-060-arestas-—-projecao-hierarquica" tabindex="-1">part_of (38.060 arestas) — Projeção hierárquica <a class="header-anchor" href="#part-of-38-060-arestas-—-projecao-hierarquica" aria-label="Permalink to &quot;part_of (38.060 arestas) — Projeção hierárquica&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nó file (level=4)</span></span>
<span class="line"><span>  └─ part_of ──→ chunk (level 0/1/2)</span></span></code></pre></div><p><strong>Direção:</strong> chunk → file (inbound no file node).<code>&lt;br&gt;</code><strong>Navegação:</strong> <code>nexus_adjacent(node_id)</code> mostra inbound=<code>part_of</code>.</p><h3 id="depends-on-imports-295-arestas-—-projecao-de-dependencia" tabindex="-1">depends_on:imports (295 arestas) — Projeção de dependência <a class="header-anchor" href="#depends-on-imports-295-arestas-—-projecao-de-dependencia" aria-label="Permalink to &quot;depends_on:imports (295 arestas) — Projeção de dependência&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>file A ──depends_on:imports──→ file B</span></span></code></pre></div><p><strong>Direção:</strong> A importa B (A → B).<code>&lt;br&gt;</code><strong>Origem:</strong> Extraído de imports TypeScript (<code>from &#39;...&#39;</code>), Rust (<code>use crate::</code>), Python, SQL (<code>REFERENCES</code>).<code>&lt;br&gt;</code><strong>Navegação:</strong> isola com <code>criteria=&#39;depends_on:imports&#39;</code>.</p><h3 id="semantic-bridge-176-arestas-transitorias-—-projecao-semantica" tabindex="-1">semantic_bridge (176 arestas, transitórias) — Projeção semântica <a class="header-anchor" href="#semantic-bridge-176-arestas-transitorias-—-projecao-semantica" aria-label="Permalink to &quot;semantic_bridge (176 arestas, transitórias) — Projeção semântica&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>file A ──semantic_bridge──→ file B</span></span></code></pre></div><p><strong>Direção:</strong> bidirecional simétrica.<code>&lt;br&gt;</code><strong>Origem:</strong> Similaridade de embedding entre summaries dos file nodes (threshold 0.80).<code>&lt;br&gt;</code><strong>Nota:</strong> Em transição — será substituído por <code>depends_on</code> mais precisos.</p><h3 id="contradicts-119-arestas-—-projecao-de-conflito" tabindex="-1">contradicts (119 arestas) — Projeção de conflito <a class="header-anchor" href="#contradicts-119-arestas-—-projecao-de-conflito" aria-label="Permalink to &quot;contradicts (119 arestas) — Projeção de conflito&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chunk A ──contradicts──→ chunk B</span></span></code></pre></div><p><strong>Direção:</strong> simétrica.<code>&lt;br&gt;</code><strong>Origem:</strong> Pipeline de enriquecimento detectou contradição semântica.</p><h2 id="_3-eixos-de-projecao" tabindex="-1">3. Eixos de Projeção <a class="header-anchor" href="#_3-eixos-de-projecao" aria-label="Permalink to &quot;3. Eixos de Projeção&quot;">​</a></h2><p>O grafo T4 é um <strong>hipergrafo multi-relacional</strong>. Toda navegação é uma <strong>fatia</strong> definida pela interseção de três eixos:</p><table tabindex="0"><thead><tr><th>Eixo</th><th>Valores</th><th>Exemplo de fatia</th></tr></thead><tbody><tr><td><code>criteria</code></td><td><code>part_of</code>, <code>depends_on:imports</code>, <code>semantic_bridge</code>, <code>contradicts</code></td><td>Só dependências</td></tr><tr><td><code>file_type</code></td><td><code>typescript</code>, <code>sql</code>, <code>rust</code>, <code>markdown</code>, <code>python</code>, ...</td><td>Só TypeScript</td></tr><tr><td><code>project</code></td><td><code>nexus</code>, <code>intraclinica-ng</code></td><td>Só intraclinica</td></tr></tbody></table><p><strong>Fatia composta:</strong> <code>criteria=depends_on:imports</code> + <code>file_type=typescript</code> + <code>project=intraclinica-ng</code> = &quot;dependências entre arquivos TypeScript do frontend&quot;</p><h2 id="_4-padroes-de-navegacao-t4" tabindex="-1">4. Padrões de Navegação T4 <a class="header-anchor" href="#_4-padroes-de-navegacao-t4" aria-label="Permalink to &quot;4. Padrões de Navegação T4&quot;">​</a></h2><h3 id="subir-chunk-→-file-node" tabindex="-1">Subir: chunk → file node <a class="header-anchor" href="#subir-chunk-→-file-node" aria-label="Permalink to &quot;Subir: chunk → file node&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T3 acha chunk → adjacent(chunk) → filtra outbound part_of → file node</span></span></code></pre></div><h3 id="descer-file-node-→-chunks" tabindex="-1">Descer: file node → chunks <a class="header-anchor" href="#descer-file-node-→-chunks" aria-label="Permalink to &quot;Descer: file node → chunks&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>adjacent(file_node) → inbound links com criteria=part_of → lista de chunks</span></span></code></pre></div><h3 id="cruzar-file-→-file-dependencias" tabindex="-1">Cruzar: file → file (dependências) <a class="header-anchor" href="#cruzar-file-→-file-dependencias" aria-label="Permalink to &quot;Cruzar: file → file (dependências)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>adjacent(file_node) → outbound com criteria=depends_on:imports → arquivos importados</span></span></code></pre></div><h3 id="cruzar-file-→-file-dominio" tabindex="-1">Cruzar: file → file (domínio) <a class="header-anchor" href="#cruzar-file-→-file-dominio" aria-label="Permalink to &quot;Cruzar: file → file (domínio)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>adjacent(file_node) → inbound/outbound com criteria=semantic_bridge → arquivos similares</span></span></code></pre></div><h3 id="filtrar-por-file-type" tabindex="-1">Filtrar por file_type <a class="header-anchor" href="#filtrar-por-file-type" aria-label="Permalink to &quot;Filtrar por file_type&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_query(&quot;... file_type:sql ...&quot;) → busca semântica filtrada por tipo</span></span>
<span class="line"><span># Ou: adjacent(file_node) → filtra nós cujo file_type bate</span></span></code></pre></div><p>A projeção por <code>file_type</code> permite ignorar formatos irrelevantes. Ex: uma query sobre &quot;regras de negócio&quot; pode ignorar JSON e YAML, focando só em TypeScript e SQL.</p><h3 id="combinar-t3-t4" tabindex="-1">Combinar: T3 + T4 <a class="header-anchor" href="#combinar-t3-t4" aria-label="Permalink to &quot;Combinar: T3 + T4&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nexus_query(&quot;...&quot;) → node_id do chunk → adjacent(node_id)</span></span>
<span class="line"><span>  → sobe (part_of) pro file node</span></span>
<span class="line"><span>  → cruza (depends_on/semantic_bridge) pra outros files</span></span>
<span class="line"><span>  → desce (part_of) pros chunks deles</span></span></code></pre></div><h2 id="_5-camadas-do-grafo-anatomia" tabindex="-1">5. Camadas do Grafo (Anatomia) <a class="header-anchor" href="#_5-camadas-do-grafo-anatomia" aria-label="Permalink to &quot;5. Camadas do Grafo (Anatomia)&quot;">​</a></h2><p>T4 tem três camadas de rigidez, como um organismo:</p><table tabindex="0"><thead><tr><th>Camada</th><th>Metáfora</th><th>Arestas</th><th>Mutabilidade</th></tr></thead><tbody><tr><td><strong>Rígida</strong> (AST)</td><td>Esqueleto</td><td><code>depends_on:imports</code></td><td>Fato — imutável. Se A importa B, a aresta existe.</td></tr><tr><td><strong>Semântica</strong></td><td>Carne</td><td><code>semantic_bridge</code>, <code>contradicts</code></td><td>Aproximação — mutável com threshold/modelo.</td></tr><tr><td><strong>Classificação</strong></td><td>Cartilagem</td><td><code>file_type</code>, <code>project</code></td><td>Metadado — classifica os nós, não as arestas.</td></tr></tbody></table><p><strong>Esqueleto (rigidez estrutural):</strong> <code>depends_on:imports</code> é verdadeiro independente de modelo. O agente confia cegamente nessas arestas pra navegação estrutural.</p><p><strong>Carne (flexibilidade semântica):</strong> <code>semantic_bridge</code> é útil pra descoberta (&quot;arquivos que parecem com X&quot;), mas pode ter falsos positivos. O agente usa como dica, não como fato.</p><p><strong>Cartilagem (classificação):</strong> <code>file_type</code> e <code>project</code> organizam os nós em categorias. O agente fatia o grafo por esses eixos pra focar no formato relevante.</p><p>Navegação ideal: <strong>esqueleto primeiro, carne depois.</strong> Sobe/desce/cruza por <code>depends_on:imports</code> pra entender a estrutura real; usa <code>semantic_bridge</code> só quando precisa explorar território desconhecido.</p><h2 id="_6-regras" tabindex="-1">6. Regras <a class="header-anchor" href="#_6-regras" aria-label="Permalink to &quot;6. Regras&quot;">​</a></h2><ol><li><strong>Nó file (level=4) é o ponto de entrada estrutural.</strong> Toda navegação começa ou termina nele.</li><li><strong>Chunks (level 0-2) só se conectam via part_of.</strong> Arestas diretas entre chunks de arquivos diferentes não existem. Conexão cross-file é SEMPRE via file node.</li><li><strong>Cada criteria × file_type × project é uma fatia independente.</strong> O mesmo par de nós pode ter múltiplas arestas de criteria diferentes, cada uma projetando um ângulo.</li><li><strong>L3 não existe mais como level fixo.</strong> A síntese de domínio emerge on-the-fly por cluster T4 (community detection), não por blob individual.</li></ol><h2 id="_7-metricas-atuais-pos-migracao" tabindex="-1">7. Métricas Atuais (pós-migração) <a class="header-anchor" href="#_7-metricas-atuais-pos-migracao" aria-label="Permalink to &quot;7. Métricas Atuais (pós-migração)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>File nodes (level=4):       899</span></span>
<span class="line"><span>Chunks (level 0+1+2):      38.566</span></span>
<span class="line"><span>  part_of edges:           38.060</span></span>
<span class="line"><span>  depends_on:imports:         295</span></span>
<span class="line"><span>  semantic_bridge:            176</span></span>
<span class="line"><span>  contradicts:                 119</span></span></code></pre></div>`,48)])])}const g=a(d,[["render",i]]);export{u as __pageData,g as default};
